import type { SentinelConfig } from "@sentinel/types";

/**
 * Generate the extension.mjs content for the GitHub Copilot CLI eval-guard extension.
 *
 * The generated file is a self-contained ES module that:
 *  1. Reads checks.yaml from the project root
 *  2. Runs deterministic checks against staged/changed files
 *  3. Presents manual check prompts to the agent
 *  4. Blocks task_complete if any check fails
 */
export function buildEngine(config: SentinelConfig): string {
  const configJson = JSON.stringify(config, null, 2);

  return `#!/usr/bin/env node
// AUTO-GENERATED by @sentinel/engine-copilot — do not edit manually.
// Re-generate with: npx sentinel update

import { execSync } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";

// ─── Embedded config (generated from checks.yaml) ────────────────────────────
const SENTINEL_CONFIG = ${configJson};

// ─── Helpers ─────────────────────────────────────────────────────────────────

function getStagedFiles() {
  try {
    const out = execSync("git diff --cached --name-only", {
      encoding: "utf8",
      stdio: ["pipe", "pipe", "ignore"],
    });
    return out.trim().split("\\n").filter(Boolean);
  } catch {
    return [];
  }
}

function matchesTrigger(trigger, changedFiles) {
  if (trigger.type === "always") return true;
  const patterns = {
    frontend: [/\\.tsx?$/, /\\.jsx?$/, /\\.css$/, /\\.scss$/],
    backend: [/\\/api\\//, /\\/server\\//, /\\/routes\\//],
    prisma: [/\\.prisma$/, /\\/prisma\\//],
    socket: [/\\/socket\\//, /\\/ws\\//],
    visual: [/\\.stories\\./, /\\.snap$/],
  };
  if (trigger.type === "custom") {
    if (!trigger.pattern) return false;
    const re = new RegExp(trigger.pattern);
    return changedFiles.some((f) => re.test(f));
  }
  const regexes = patterns[trigger.type] ?? [];
  return changedFiles.some((f) => regexes.some((re) => re.test(f)));
}

function runCheck(check) {
  if (!check.cmd) return { status: "pending" };
  try {
    const output = execSync(check.cmd, { encoding: "utf8", timeout: 60000, stdio: "pipe" });
    return { status: "pass", output };
  } catch (e) {
    const output = [e.stdout, e.stderr].filter(Boolean).join("\\n");
    return { status: "fail", output, exitCode: e.status ?? 1 };
  }
}

// ─── Extension entry-point ────────────────────────────────────────────────────

export default {
  // Invoked before the agent marks a task complete
  async beforeTaskComplete({ toolInput }) {
    const changedFiles = getStagedFiles();
    const failures = [];

    for (const check of SENTINEL_CONFIG.deterministic) {
      if (!matchesTrigger(check.trigger, changedFiles)) continue;
      const result = runCheck(check);
      if (result.status === "fail") {
        failures.push({ check, result });
      }
    }

    if (failures.length > 0) {
      const summary = failures
        .map((f) => \`  ✗ [\${f.check.label}]\\n\${(f.result.output ?? "").trim()}\`)
        .join("\\n\\n");
      return {
        decision: "block",
        reason: \`Sentinel eval-guard: \${failures.length} check(s) failed:\\n\\n\${summary}\\n\\nFix the above issues before marking the task complete.\`,
      };
    }

    // Surface manual checks as a reminder
    const manualChecks = SENTINEL_CONFIG.manual.filter((c) =>
      matchesTrigger(c.trigger, changedFiles),
    );
    if (manualChecks.length > 0) {
      const list = manualChecks.map((c) => \`  □ [\${c.label}] \${c.manual ?? ""}\`).join("\\n");
      console.log(\`[sentinel] Manual checks to confirm:\\n\${list}\\n\`);
    }

    return { decision: "allow" };
  },
};
`;
}
